  /** Returns rendering statistics for the current frame */
  getRenderStats(): IRenderStats {
    const s = this.handle.get_render_stats();
    if (!s) return { drawCalls: 0, triangles: 0, textureBinds: 0, shaderBinds: 0 };
    return { drawCalls: s.draw_calls, triangles: s.triangles, textureBinds: s.texture_binds, shaderBinds: 0 };
  }

  /** Creates a new empty entity */
  spawnEmpty(): IEntity { return new WebEntity(this.handle.spawn_empty()); }
  /** Spawns multiple empty entities at once */
  spawnBatch(count: number): IEntity[] {
    const arr = this.handle.spawn_batch(count);
    return Array.from(arr, bits => new WebEntity(bits));
  }
  /** Destroys an entity and all its components */
  despawn(entity: IEntity): boolean { return this.handle.despawn(entity.toBits()); }
  /** Despawns multiple entities at once */
  despawnBatch(entities: IEntity[]): number {
    const bits = BigUint64Array.from(entities.map(e => e.toBits()));
    return this.handle.despawn_batch(bits);
  }
  /** Returns the number of living entities */
  entityCount(): number { return this.handle.entity_count(); }
  /** Returns true if the entity still exists */
  isAlive(entity: IEntity): boolean { return this.handle.is_alive(entity.toBits()); }
  /** Clones an entity, creating a new entity with copies of all cloneable components */
  cloneEntity(entity: IEntity): IEntity { return new WebEntity(this.handle.clone_entity(entity.toBits())); }
  /** Clones an entity and all its descendants recursively */
  cloneEntityRecursive(entity: IEntity): IEntity { return new WebEntity(this.handle.clone_entity_recursive(entity.toBits())); }

  /** Attaches a Transform2D component to the entity */
  addTransform2d(entity: IEntity, t: ITransform2DData): void { this.handle.add_transform2d(entity.toBits(), t.positionX, t.positionY, t.rotation, t.scaleX, t.scaleY); }
  /** Returns the entity's Transform2D, or null if absent */
  getTransform2d(entity: IEntity): ITransform2DData | null {
    const t = this.handle.get_transform2d(entity.toBits());
    if (!t) return null;
    return { positionX: t.position_x, positionY: t.position_y, rotation: t.rotation, scaleX: t.scale_x, scaleY: t.scale_y };
  }
  /** Overwrites the entity's Transform2D */
  setTransform2d(entity: IEntity, t: ITransform2DData): void { this.handle.set_transform2d(entity.toBits(), t.positionX, t.positionY, t.rotation, t.scaleX, t.scaleY); }
  /** Returns true if the entity has a Transform2D */
  hasTransform2d(entity: IEntity): boolean { return this.handle.has_transform2d(entity.toBits()); }
